+    let manifest: Value = serde_json::from_str(&manifest_bytes).expect("parse manifest json");
+    let assets = manifest["assets"].as_array().expect("assets array");
+    assert_eq!(
+        assets.len(),
+        3,
+        "initial IFC corpus should include three category seeds"
+    );
+
+    for asset in assets {
